/* 小守護 Socket.IO 安全備援版
 * 沒有真正 socket.io client 時，提供 no-op client，Dashboard 會自動改用輪詢。
 */
(function () {
  if (typeof window === "undefined" || typeof window.io === "function") return;
  window.io = function socketIoClientShim() {
    const handlers = {};
    const socket = {
      connected: false,
      disconnected: true,
      id: null,
      on(event, handler) { handlers[event] = handler; return socket; },
      once(event, handler) { handlers[event] = handler; return socket; },
      off(event) { delete handlers[event]; return socket; },
      emit() { return socket; },
      connect() {
        setTimeout(() => {
          if (typeof handlers.connect_error === "function") {
            handlers.connect_error(new Error("即時通道未載入，已改用輪詢模式"));
          }
        }, 0);
        return socket;
      },
      disconnect() { socket.connected = false; socket.disconnected = true; return socket; },
      close() { return socket.disconnect(); }
    };
    return socket;
  };
  window.io.__AI_SHIELD_NO_THROW_SHIM__ = true;
})();
